  (201, 'Awakening', 'Whenever you use MP during battle, your Awakening bar will fill up. This allows you to perform certain special skills which consume Awakening points. These skills also consume MP, however the MP they consume does not fill your awakening bar.', '/skill-icons/201.webp', 0, '{25}', 'Archer', 60, 1, 0, '[]'::jsonb, '{"25":[3,5,0]}'::jsonb, '[{"level":1,"reqLevel":60,"sp":1,"mp":0,"cooldown":0,"castTime":0,"range":0,"power":null,"description":"Whenever you use MP during battle, your Awakening bar will fill up. This allows you to perform certain special skills which consume Awakening points. These skills also consume MP, however the MP they consume does not fill your awakening bar."}]'::jsonb),
