  (203, 'Ice Shower', '[Awakening Skill] Summon the Wind Saber to shoot an ice feather arrow. Can hit up to 10 enemies with a level 6 freezing effect. Arrow number and damage is increased with skill level.', '/skill-icons/203.webp', 0, '{25}', 'Archer', 60, 5, 0, '[{"id":201,"level":1}]'::jsonb, '{"25":[3,4,3]}'::jsonb, '[{"level":1,"reqLevel":60,"sp":25,"mp":420,"cooldown":30000,"castTime":0,"range":0,"power":"35%","description":"[Awakening Skill] Summon the Wind Saber to shoot an ice feather arrow. Can hit up to 10 enemies with a level 6 freezing effect. Arrow number and damage is increased with skill level."},{"level":2,"reqLevel":63,"sp":25,"mp":440,"cooldown":25000,"castTime":0,"range":0,"power":"50%","description":"[Awakening Skill] Summon the Wind Saber to shoot an ice feather arrow. Can hit up to 12 enemies with a level 7 freezing effect. Arrow number and damage is increased with skill level."},{"level":3,"reqLevel":66,"sp":25,"mp":460,"cooldown":20000,"castTime":0,"range":0,"power":"60%","description":"[Awakening Skill] Summon the Wind Saber to shoot an ice feather arrow. Can hit up to 14 enemies with a level 8 freezing effect. Arrow number and damage is increased with skill level."},{"level":4,"reqLevel":69,"sp":25,"mp":480,"cooldown":17000,"castTime":0,"range":0,"power":"70%","description":"[Awakening Skill] Summon the Wind Saber to shoot an ice feather arrow. Can hit up to 16 enemies with a level 9 freezing effect. Arrow number and damage is increased with skill level."},{"level":5,"reqLevel":72,"sp":25,"mp":500,"cooldown":15000,"castTime":0,"range":0,"power":"80%","description":"[Awakening Skill] Summon the Wind Saber to shoot an ice feather arrow. Can hit up to 18 enemies with a level 10 freezing effect. Arrow number and damage is increased with skill level."}]'::jsonb),
  (204, 'Multi Stripe', '[Ultimate Skill] The Ultimate Sentinel Technique. Rains a hail of razor sharp feathers onto the battlefield. Attacks up to 20 monsters with 60 feathers and a final bombing attack by Wind Saber. During casting, character will be unbeatable.', '/skill-icons/204.webp', 0, '{25}', 'Archer', 60, 1, 0, '[{"id":201,"level":1}]'::jsonb, '{"25":[3,6,3]}'::jsonb, '[{"level":1,"reqLevel":60,"sp":60,"mp":0,"cooldown":300000,"castTime":0,"range":0,"power":"100%","description":"[Ultimate Skill] The Ultimate Sentinel Technique. Rains a hail of razor sharp feathers onto the battlefield. Attacks up to 20 monsters with 60 feathers and a final bombing attack by Wind Saber. During casting, character will be unbeatable."}]'::jsonb),
  (205, 'Wind Blade', '[Awakening Skill] Summon the Wind Saber to attack up to 10 enemies 3 times in the range with a sharp wind. Targets will suffer a level 6 bleeding effect.', '/skill-icons/205.webp', 0, '{25}', 'Archer', 62, 5, 0, '[{"id":203,"level":1}]'::jsonb, '{"25":[3,4,5]}'::jsonb, '[{"level":1,"reqLevel":62,"sp":25,"mp":420,"cooldown":30000,"castTime":0,"range":0,"power":"100%","description":"[Awakening Skill] Summon the Wind Saber to attack up to 10 enemies 3 times in the range with a sharp wind. Targets will suffer a level 6 bleeding effect."},{"level":2,"reqLevel":64,"sp":25,"mp":440,"cooldown":25000,"castTime":0,"range":0,"power":"115%","description":"[Awakening Skill] Summon the Wind Saber to attack up to 12 enemies 4 times in the range with a sharp wind. Targets will suffer a level 7 bleeding effect"},{"level":3,"reqLevel":66,"sp":25,"mp":460,"cooldown":20000,"castTime":0,"range":0,"power":"130%","description":"[Awakening Skill] Summon the Wind Saber to attack up to 14 enemies 5 times in the range with a sharp wind. Targets will suffer a level 8 bleeding effect."},{"level":4,"reqLevel":68,"sp":25,"mp":480,"cooldown":17000,"castTime":0,"range":0,"power":"145%","description":"[Awakening Skill] Summon the Wind Saber to attack up to 16 enemies 6 times in the range with a sharp wind. Targets will suffer a level 9 bleeding effect."},{"level":5,"reqLevel":70,"sp":25,"mp":500,"cooldown":15000,"castTime":0,"range":0,"power":"160%","description":"[Awakening Skill] Summon the Wind Saber to attack up to 18 enemies 7 times in the range with a sharp wind. Targets will suffer a level 7 bleeding effect."}]'::jsonb),
  (206, 'Wire Action', 'Throw 5 hooks forward to drags targets towards you while inflicting a level 1 stun. The higher the skill level, the greater the efficiency. One hook can drag 2 enemies.', '/skill-icons/206.webp', 0, '{25}', 'Archer', 60, 5, 0, '[]'::jsonb, '{"25":[3,1,0]}'::jsonb, '[{"level":1,"reqLevel":60,"sp":20,"mp":80,"cooldown":15000,"castTime":0,"range":0,"power":null,"description":"Throw 5 hooks forward to drags targets towards you while inflicting a level 1 stun. The higher the skill level, the greater the efficiency. One hook can drag 2 enemies."},{"level":2,"reqLevel":63,"sp":20,"mp":100,"cooldown":12500,"castTime":0,"range":0,"power":null,"description":"Throw 5 hooks forward to drags targets towards you while inflicting a level 1 stun. The higher the skill level, the greater the efficiency. One hook can drag 3 enemies."},{"level":3,"reqLevel":66,"sp":20,"mp":120,"cooldown":10000,"castTime":0,"range":0,"power":null,"description":"Throw 5 hooks forward to drags targets towards you while inflicting a level 2 stun. The higher the skill level, the greater the efficiency. One hook can drag 4 enemies."},{"level":4,"reqLevel":69,"sp":20,"mp":140,"cooldown":7500,"castTime":0,"range":0,"power":null,"description":"Throw 5 hooks forward to drags targets towards you while inflicting a level 2 stun. The higher the skill level, the greater the efficiency. One hook can drag 5 enemies."},{"level":5,"reqLevel":72,"sp":20,"mp":160,"cooldown":5000,"castTime":0,"range":0,"power":null,"description":"Throw 5 hooks forward to drags targets towards you while inflicting a level 3 stun. The higher the skill level, the greater the efficiency. One hook can drag 6 enemies."}]'::jsonb),
