  (208, 'Crux Shot', 'Amplify Physical Attack Power by 12% for the next attack. Increase critical rate by 10% and attack rate will be increased. Damage of skill attack is also affected.', '/skill-icons/208.webp', 0, '{26}', 'Archer', 20, 5, 0, '[]'::jsonb, '{"26":[1,3,1]}'::jsonb, '[{"level":1,"reqLevel":20,"sp":15,"mp":22,"cooldown":100,"castTime":0,"range":0,"power":null,"description":"Amplify Physical Attack Power by 12% for the next attack. Increase critical rate by 10% and attack rate will be increased. Damage of skill attack is also affected."},{"level":2,"reqLevel":24,"sp":15,"mp":24,"cooldown":100,"castTime":0,"range":0,"power":null,"description":"Amplify Physical Attack Power by 14% for the next attack. Increase critical rate by 12% and attack rate will be increased. Damage of skill attack is also affected."},{"level":3,"reqLevel":28,"sp":15,"mp":26,"cooldown":100,"castTime":0,"range":0,"power":null,"description":"Amplify Physical Attack Power by 16% for the next attack. Increase critical rate by 14% and attack rate will be increased. Damage of skill attack is also affected."},{"level":4,"reqLevel":32,"sp":15,"mp":28,"cooldown":100,"castTime":0,"range":0,"power":null,"description":"Amplify Physical Attack Power by 18% for the next attack. Increase critical rate by 16% and attack rate will be increased. Damage of skill attack is also affected."},{"level":5,"reqLevel":36,"sp":15,"mp":30,"cooldown":100,"castTime":0,"range":0,"power":null,"description":"Amplify Physical Attack Power by 20% for the next attack. Increase critical rate by 18% and attack rate will be increased. Damage of skill attack is also affected."}]'::jsonb),
